def perceive(data):
    text = str(data)
    num = ""
    seen_digit = False
    for ch in text:
        if ch.isdigit():
            num += ch
            seen_digit = True
        elif ch in ".-" and not (ch == "." and "." in num):
            num += ch
        elif seen_digit:
            break
    try:
        value = float(num)
    except (ValueError, TypeError):
        return {}
    return {"temperature_c": value}
